window.EigoData.listening = window.EigoData.listening.concat([
  {"id":"lg8_d800","type":"dictation","level":"A2","text":"Let's split the bill.","ja":"割り勘にしましょう。"},
  {"id":"lg8_d801","type":"dictation","level":"A2","text":"It's on me.","ja":"私のおごりです。"},
  {"id":"lg8_d802","type":"dictation","level":"A2","text":"Help yourself.","ja":"ご自由にどうぞ。"},
  {"id":"lg8_d803","type":"dictation","level":"A2","text":"Make yourself at home.","ja":"くつろいでください。"},
  {"id":"lg8_d804","type":"dictation","level":"A2","text":"I'll walk you out.","ja":"お見送りします。"},
  {"id":"lg8_d805","type":"dictation","level":"A2","text":"Drive safely.","ja":"気をつけて運転して。"},
  {"id":"lg8_d806","type":"dictation","level":"A2","text":"Give me a call later.","ja":"あとで電話して。"},
  {"id":"lg8_d807","type":"dictation","level":"A2","text":"Let's keep in touch.","ja":"連絡を取り合いましょう。"},
  {"id":"lg8_d808","type":"dictation","level":"A2","text":"It was nice meeting you.","ja":"お会いできてよかったです。"},
  {"id":"lg8_d809","type":"dictation","level":"A2","text":"Send my regards to your family.","ja":"ご家族によろしく。"},
  {"id":"lg8_d810","type":"dictation","level":"B1","text":"Let me introduce my colleague.","ja":"同僚を紹介します。"},
  {"id":"lg8_d811","type":"dictation","level":"B1","text":"We've heard a lot about you.","ja":"お噂はかねがね。"},
  {"id":"lg8_d812","type":"dictation","level":"B1","text":"Thanks for having us.","ja":"お招きありがとうございます。"},
  {"id":"lg8_d813","type":"dictation","level":"B1","text":"I'll let you get back to work.","ja":"お仕事に戻ってください。"},
  {"id":"lg8_d814","type":"dictation","level":"B1","text":"Shall we get started?","ja":"始めましょうか。"},
  {"id":"lg8_d815","type":"dictation","level":"B1","text":"Let's take a short break.","ja":"少し休憩しましょう。"},
  {"id":"lg8_d816","type":"dictation","level":"B1","text":"Could we go over that again?","ja":"もう一度確認できますか。"},
  {"id":"lg8_d817","type":"dictation","level":"B1","text":"I'll take that into consideration.","ja":"検討させていただきます。"},
  {"id":"lg8_d818","type":"dictation","level":"B1","text":"Let's touch base next week.","ja":"来週また連絡しましょう。"},
  {"id":"lg8_d819","type":"dictation","level":"B1","text":"I'll pencil you in for Tuesday.","ja":"火曜で仮に入れておきます。"},
  {"id":"lg8_d820","type":"dictation","level":"B2","text":"I want to flag a concern about scope creep.","ja":"スコープの肥大化を懸念として挙げたいです。"},
  {"id":"lg8_d821","type":"dictation","level":"B2","text":"Let's establish clear ownership for each task.","ja":"各タスクの責任者を明確にしましょう。"},
  {"id":"lg8_d822","type":"dictation","level":"B2","text":"We should document the decision and rationale.","ja":"決定と根拠を記録すべきです。"},
  {"id":"lg8_d823","type":"dictation","level":"B2","text":"Could we revisit the assumptions behind this?","ja":"この前提を見直せますか。"},
  {"id":"lg8_d824","type":"dictation","level":"B2","text":"Let's timebox the discussion to ten minutes.","ja":"議論は10分に区切りましょう。"},
  {"id":"lg8_d825","type":"dictation","level":"B2","text":"I'll circulate the notes after the call.","ja":"通話後にメモを共有します。"},
  {"id":"lg8_d826","type":"dictation","level":"B2","text":"We need a contingency plan just in case.","ja":"念のため代替案が必要です。"},
  {"id":"lg8_d827","type":"dictation","level":"B2","text":"Let's not let perfect be the enemy of good.","ja":"完璧を求めて前に進めないのは避けましょう。"},
  {"id":"lg8_d828","type":"dictation","level":"B2","text":"I'd like to align on success metrics first.","ja":"まず成功指標をすり合わせたいです。"},
  {"id":"lg8_d829","type":"dictation","level":"B2","text":"Let's park that and follow up offline.","ja":"それは保留にして別途対応しましょう。"},
  {"id":"lg8_d830","type":"dictation","level":"B1","text":"Could you recommend a good restaurant nearby?","ja":"近くの良いお店を教えてもらえますか。"},
  {"id":"lg8_d831","type":"dictation","level":"B1","text":"Is this dish spicy?","ja":"この料理は辛いですか。"},
  {"id":"lg8_d832","type":"dictation","level":"B1","text":"Could we sit by the window?","ja":"窓際に座れますか。"},
  {"id":"lg8_d833","type":"dictation","level":"B1","text":"Do you take reservations?","ja":"予約は受け付けていますか。"},
  {"id":"lg8_d834","type":"dictation","level":"B1","text":"What do you recommend?","ja":"おすすめは何ですか。"},
  {"id":"lg8_c800","type":"comprehension","level":"B1","text":"Hi everyone, before we begin, please make sure your microphones are muted unless you're speaking. We'll take questions at the end.","question":"発言時以外は?","choices":["マイクをミュート","カメラをオフ","チャットを使う","退出する"],"answer":"マイクをミュート","ja":"発言時以外はマイクをミュート。質問は最後に。"},
  {"id":"lg8_c801","type":"comprehension","level":"B1","text":"The package requires a signature on delivery. If no one is home, the driver will leave a note for redelivery.","question":"不在時はどうなる?","choices":["再配達の通知が残る","持ち帰り処分","玄関に放置","返送"],"answer":"再配達の通知が残る","ja":"配達には署名が必要。不在なら再配達の通知を残す。"},
  {"id":"lg8_c802","type":"comprehension","level":"B2","text":"Our analysis shows users drop off at the payment step. I suggest simplifying the form and adding more payment options.","question":"提案は?","choices":["フォーム簡素化と決済追加","値下げ","広告増","アプリ刷新"],"answer":"フォーム簡素化と決済追加","ja":"決済段階で離脱。フォーム簡素化と決済手段追加を提案。"},
  {"id":"lg8_c803","type":"comprehension","level":"B2","text":"We're piloting the new workflow with one team first. If it improves output, we'll roll it out company-wide next quarter.","question":"まず何をする?","choices":["1チームで試験導入","全社展開","外注","中止"],"answer":"1チームで試験導入","ja":"まず1チームで試験導入し、効果があれば来期に全社展開。"},
  {"id":"lg8_c804","type":"comprehension","level":"B2","text":"The venue holds two hundred, but we expect three hundred. We should either find a bigger space or run two sessions.","question":"問題は?","choices":["定員超過","予算不足","日程重複","機材不足"],"answer":"定員超過","ja":"会場は200人だが300人見込み。大きな会場か2回開催を検討。"}
]);


