window.EigoData.listening = window.EigoData.listening.concat([
  {"id":"lgA_d1000","type":"dictation","level":"A2","text":"Could you repeat that more slowly?","ja":"もう少しゆっくり言ってもらえますか？"},
  {"id":"lgA_d1001","type":"dictation","level":"A2","text":"How do you spell your name?","ja":"お名前のつづりは？"},
  {"id":"lgA_d1002","type":"dictation","level":"A2","text":"What's your phone number?","ja":"電話番号は？"},
  {"id":"lgA_d1003","type":"dictation","level":"A2","text":"Could you write it down for me?","ja":"書いてもらえますか？"},
  {"id":"lgA_d1004","type":"dictation","level":"A2","text":"I didn't quite catch your name.","ja":"お名前を聞き取れませんでした。"},
  {"id":"lgA_d1006","type":"dictation","level":"A2","text":"Does Thursday work for you?","ja":"木曜は都合いいですか？"},
  {"id":"lgA_d1007","type":"dictation","level":"A2","text":"I'm afraid I'm busy then.","ja":"あいにくその時は忙しいです。"},
  {"id":"lgA_d1008","type":"dictation","level":"A2","text":"How about the following week?","ja":"翌週はどうですか？"},
  {"id":"lgA_d1009","type":"dictation","level":"A2","text":"That works perfectly.","ja":"それで完璧です。"},
  {"id":"lgA_d1010","type":"dictation","level":"B1","text":"I'd like to confirm our appointment.","ja":"予約を確認したいのですが。"},
  {"id":"lgA_d1011","type":"dictation","level":"B1","text":"Can we move it up an hour?","ja":"1時間早められますか？"},
  {"id":"lgA_d1012","type":"dictation","level":"B1","text":"Something's come up, unfortunately.","ja":"あいにく用事ができました。"},
  {"id":"lgA_d1013","type":"dictation","level":"B1","text":"Let's find another time that suits.","ja":"別の都合の良い時間を探しましょう。"},
  {"id":"lgA_d1014","type":"dictation","level":"B1","text":"I'll text you the address.","ja":"住所をテキストで送ります。"},
  {"id":"lgA_d1015","type":"dictation","level":"B1","text":"Could you send me directions?","ja":"道順を送ってもらえますか？"},
  {"id":"lgA_d1016","type":"dictation","level":"B1","text":"I'm running about ten minutes late.","ja":"10分ほど遅れています。"},
  {"id":"lgA_d1017","type":"dictation","level":"B1","text":"No worries, take your time.","ja":"大丈夫、ゆっくりどうぞ。"},
  {"id":"lgA_d1018","type":"dictation","level":"B1","text":"We're just about to start.","ja":"ちょうど始まるところです。"},
  {"id":"lgA_d1019","type":"dictation","level":"B1","text":"Can you hear me okay?","ja":"聞こえていますか？"},
  {"id":"lgA_d1020","type":"dictation","level":"B2","text":"Your connection keeps cutting out.","ja":"接続が途切れ続けています。"},
  {"id":"lgA_d1021","type":"dictation","level":"B2","text":"Let me share my screen.","ja":"画面を共有します。"},
  {"id":"lgA_d1022","type":"dictation","level":"B2","text":"Can everyone see the slide?","ja":"スライドは皆さん見えますか？"},
  {"id":"lgA_d1023","type":"dictation","level":"B2","text":"Let's go around and introduce ourselves.","ja":"順番に自己紹介しましょう。"},
  {"id":"lgA_d1024","type":"dictation","level":"B2","text":"I'll drop the link in the chat.","ja":"チャットにリンクを貼ります。"},
  {"id":"lgA_d1025","type":"dictation","level":"B2","text":"Could you mute when not speaking?","ja":"発言時以外はミュートにしてください。"},
  {"id":"lgA_d1026","type":"dictation","level":"B2","text":"Let's park questions until the end.","ja":"質問は最後までお待ちください。"},
  {"id":"lgA_d1027","type":"dictation","level":"B2","text":"I'll follow up with action items.","ja":"アクション項目を後で共有します。"},
  {"id":"lgA_d1028","type":"dictation","level":"B2","text":"Thanks everyone, let's wrap up.","ja":"皆さんありがとう、締めましょう。"},
  {"id":"lgA_d1029","type":"dictation","level":"B2","text":"I'll send the recording afterward.","ja":"録画を後で送ります。"},
  {"id":"lgA_d1030","type":"dictation","level":"B1","text":"Could I have a window seat?","ja":"窓側の席をお願いできますか？"},
  {"id":"lgA_d1031","type":"dictation","level":"B1","text":"Is there a vegetarian option?","ja":"ベジタリアン向けはありますか？"},
  {"id":"lgA_d1032","type":"dictation","level":"B1","text":"How long is the layover?","ja":"乗り継ぎ時間はどのくらいですか？"},
  {"id":"lgA_d1033","type":"dictation","level":"B1","text":"Where do I collect my baggage?","ja":"荷物はどこで受け取りますか？"},
  {"id":"lgA_d1034","type":"dictation","level":"B1","text":"Is the lounge this way?","ja":"ラウンジはこちらですか？"},
  {"id":"lgA_c1000","type":"comprehension","level":"B1","text":"Thank you for calling. Our office hours are nine to five, Monday through Friday. Please leave a message and we'll return your call.","question":"営業時間は?","choices":["平日9時から5時","24時間","週末のみ","10時から6時"],"answer":"平日9時から5時","ja":"平日9-17時。留守電にメッセージを。"},
  {"id":"lgA_c1001","type":"comprehension","level":"B1","text":"To reset your password, click the link in the email we just sent. The link expires in thirty minutes for security.","question":"リンクの有効時間は?","choices":["30分","24時間","1時間","無期限"],"answer":"30分","ja":"パスワード再設定のリンクは30分で失効。"},
  {"id":"lgA_c1002","type":"comprehension","level":"B2","text":"We've reviewed both vendors. One is cheaper, but the other offers better support. Given our small team, support matters more, so let's go with the second.","question":"選ぶ理由は?","choices":["サポートを重視","価格を重視","納期","知名度"],"answer":"サポートを重視","ja":"小規模チームゆえサポート重視で2社目を選択。"},
  {"id":"lgA_c1003","type":"comprehension","level":"B2","text":"The feature is technically ready, but the documentation isn't. Let's delay the release by a few days so users aren't left confused.","question":"延期の理由は?","choices":["文書が未完成","バグ","予算","人手不足"],"answer":"文書が未完成","ja":"機能は完成だが文書が未完成。利用者の混乱を避け数日延期。"},
  {"id":"lgA_c1004","type":"comprehension","level":"B2","text":"Our return rate is high for this product. Most complaints mention sizing. We should add a detailed size guide before reordering stock.","question":"追加すべきものは?","choices":["詳細なサイズ表","割引","広告","新色"],"answer":"詳細なサイズ表","ja":"返品が多くサイズに関する苦情が多い。詳細なサイズ表を追加すべき。"}
]);


